import{_ as n,C as l,o,c as s,E as t,w as i,a as r,a0 as c}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Iceland Healthcare & HRT","description":"Transgender healthcare access in Iceland","frontmatter":{"layout":"doc","title":"Iceland Healthcare & HRT","description":"Transgender healthcare access in Iceland"},"headers":[],"relativePath":"europe/iceland/healthcare.md","filePath":"europe/iceland/healthcare.md","lastUpdated":null}'),d={name:"europe/iceland/healthcare.md"};function h(m,e,p,u,g,f){const a=l("Badge");return o(),s("div",null,[t(a,{variant:"green"},{default:i(()=>[...e[0]||(e[0]=[r("Informed Consent",-1)])]),_:1}),t(a,{variant:"blue"},{default:i(()=>[...e[1]||(e[1]=[r("Public Healthcare",-1)])]),_:1}),t(a,{variant:"yellow"},{default:i(()=>[...e[2]||(e[2]=[r("Landspítali Hospital",-1)])]),_:1}),e[3]||(e[3]=c('<h1 id="healthcare-hrt-in-iceland" tabindex="-1">Healthcare &amp; HRT in Iceland <a class="header-anchor" href="#healthcare-hrt-in-iceland" aria-label="Permalink to &quot;Healthcare &amp; HRT in Iceland&quot;">​</a></h1><h2 id="informed-consent-model" tabindex="-1">Informed Consent Model <a class="header-anchor" href="#informed-consent-model" aria-label="Permalink to &quot;Informed Consent Model&quot;">​</a></h2><p>Iceland operates an <strong>informed consent model</strong> for hormone replacement therapy (HRT). This means:</p><ul><li><strong>No psychiatric diagnosis required</strong> to access HRT</li><li>Patients must be <strong>18+</strong> (16-18 with parental consent)</li><li>Treatment decisions made jointly between patient and endocrinologist</li><li>Focus on patient autonomy and informed decision-making</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-initial-consultation" tabindex="-1">Step 1: Initial Consultation <a class="header-anchor" href="#step-1-initial-consultation" aria-label="Permalink to &quot;Step 1: Initial Consultation&quot;">​</a></h3><ul><li>Contact <strong>Landspítali University Hospital</strong>, Endocrinology Department</li><li>Primary referral can be from a general practitioner (GP) or self-referral</li><li>English-speaking staff available</li></ul><h3 id="step-2-assessment" tabindex="-1">Step 2: Assessment <a class="header-anchor" href="#step-2-assessment" aria-label="Permalink to &quot;Step 2: Assessment&quot;">​</a></h3><ul><li>Medical history review</li><li>Discussion of treatment goals and potential effects</li><li>Blood tests for hormone levels</li><li>Fertility preservation options discussed</li></ul><h3 id="step-3-treatment-commencement" tabindex="-1">Step 3: Treatment Commencement <a class="header-anchor" href="#step-3-treatment-commencement" aria-label="Permalink to &quot;Step 3: Treatment Commencement&quot;">​</a></h3><ul><li>Hormones prescribed after informed consent consultation</li><li>Follow-up appointments every 3-6 months initially</li><li>Ongoing monitoring of hormone levels and health markers</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Landspítali Endocrinology</td><td>Reykjavík</td><td>HRT, monitoring, comprehensive care</td></tr><tr><td>Private endocrinologists</td><td>Reykjavík</td><td>HRT (limited availability, shorter wait times)</td></tr><tr><td>Primary care clinics</td><td>Nationwide</td><td>Initial referrals, blood work</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU/EEA prescriptions</strong>: Valid in Iceland under mutual recognition</li><li><strong>Non-EU prescriptions</strong>: May require verification by Icelandic doctor</li><li><strong>Carrying medication</strong>: Keep in original packaging with prescription labels</li><li><strong>Import</strong>: Carry a doctor&#39;s letter explaining the medication and necessity</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li>Gender-affirming surgeries are available through the public healthcare system</li><li>Referral required from Landspítali endocrinology team</li><li>Wait times can be significant (6-12 months for consultation)</li><li>Some surgeries available through private providers</li><li>Many Icelanders travel abroad for surgery (Thailand, Spain, Germany)</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><ul><li><strong>Public healthcare</strong>: HRT and consultations are heavily subsidized</li><li><strong>Prescription costs</strong>: Around 1,000-3,000 ISK per month ($7-22 USD)</li><li><strong>Private care</strong>: More expensive but shorter wait times</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.landspitali.is/" target="_blank" rel="noreferrer">Landspítali National Hospital</a></li><li><a href="https://www.landlaeknir.is/" target="_blank" rel="noreferrer">Directorate of Health</a></li><li><a href="https://trans.is/" target="_blank" rel="noreferrer">Trans Iceland - Healthcare Guide</a></li></ul>',21))])}const k=n(d,[["render",h]]);export{y as __pageData,k as default};
